"use client";

import { useSelf, useOthers } from "@liveblocks/react/suspense";
import { useState } from "react";

const AVATAR_SIZE = 36;
const MAX_VISIBLE = 4;

function getInitials(name: string): string {
  return name
    .split(" ")
    .map((part) => part[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

interface AvatarProps {
  userId: string;
  name: string;
  avatar: string;
  color: string;
  isSelf: boolean;
  zIndex: number;
}

function Avatar({ userId, name, avatar, color, isSelf, zIndex }: AvatarProps) {
  const [imgError, setImgError] = useState(false);
  const tooltipText = isSelf ? `${name} (You)` : name;

  return (
    <div
      data-testid="avatar-item"
      data-user-id={userId}
      data-self={isSelf ? "true" : undefined}
      style={{
        position: "relative",
        width: AVATAR_SIZE,
        height: AVATAR_SIZE,
        flexShrink: 0,
        zIndex,
      }}
    >
      {/* Tooltip */}
      <div
        data-testid="avatar-tooltip"
        role="tooltip"
        style={{
          position: "absolute",
          bottom: "calc(100% + 6px)",
          left: "50%",
          transform: "translateX(-50%)",
          backgroundColor: "#1f2937",
          color: "#fff",
          fontSize: 12,
          whiteSpace: "nowrap",
          padding: "3px 8px",
          borderRadius: 4,
          pointerEvents: "none",
          opacity: 0,
          transition: "opacity 0.15s",
          zIndex: 100,
        }}
        className="avatar-tooltip"
      >
        {tooltipText}
      </div>

      {/* Avatar circle */}
      <div
        style={{
          width: AVATAR_SIZE,
          height: AVATAR_SIZE,
          borderRadius: "50%",
          border: `2.5px solid ${color}`,
          overflow: "hidden",
          backgroundColor: "#e5e7eb",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 13,
          fontWeight: 600,
          color: "#374151",
          cursor: "default",
          boxSizing: "border-box",
        }}
      >
        {!imgError && avatar ? (
          <img
            src={avatar}
            alt={name}
            width={AVATAR_SIZE}
            height={AVATAR_SIZE}
            style={{ objectFit: "cover", width: "100%", height: "100%" }}
            onError={() => setImgError(true)}
          />
        ) : (
          <span>{getInitials(name)}</span>
        )}
      </div>

      {/* Online dot */}
      <div
        data-testid="online-dot"
        style={{
          position: "absolute",
          bottom: 0,
          right: 0,
          width: 10,
          height: 10,
          borderRadius: "50%",
          backgroundColor: "#22c55e",
          border: "2px solid #fff",
        }}
      />

      <style>{`
        [data-testid="avatar-item"]:hover .avatar-tooltip {
          opacity: 1 !important;
        }
      `}</style>
    </div>
  );
}

export function AvatarStack() {
  const self = useSelf();
  const others = useOthers();

  if (!self) return null;

  // Sort others by connectionId ascending for stable ordering
  const sortedOthers = [...others].sort((a, b) => a.connectionId - b.connectionId);

  // Build the full list: self first, then others
  const allUsers = [
    {
      userId: self.id,
      name: self.info?.name ?? "Unknown",
      avatar: self.info?.avatar ?? "",
      color: self.info?.color ?? "#6b7280",
      isSelf: true,
    },
    ...sortedOthers.map((other) => ({
      userId: other.id,
      name: other.info?.name ?? "Unknown",
      avatar: other.info?.avatar ?? "",
      color: other.info?.color ?? "#6b7280",
      isSelf: false,
    })),
  ];

  const visibleUsers = allUsers.slice(0, MAX_VISIBLE);
  const overflowCount = allUsers.length - MAX_VISIBLE;

  return (
    <div
      data-testid="avatar-stack"
      style={{
        display: "flex",
        alignItems: "center",
        flexDirection: "row",
        gap: 0,
      }}
    >
      {visibleUsers.map((user, index) => (
        <div
          key={user.userId}
          style={{
            marginLeft: index === 0 ? 0 : -8,
            zIndex: MAX_VISIBLE - index,
          }}
        >
          <Avatar
            userId={user.userId}
            name={user.name}
            avatar={user.avatar}
            color={user.color}
            isSelf={user.isSelf}
            zIndex={MAX_VISIBLE - index}
          />
        </div>
      ))}

      {overflowCount > 0 && (
        <div
          data-testid="avatar-overflow"
          style={{
            marginLeft: -8,
            width: AVATAR_SIZE,
            height: AVATAR_SIZE,
            borderRadius: "50%",
            backgroundColor: "#e5e7eb",
            border: "2.5px solid #9ca3af",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 12,
            fontWeight: 600,
            color: "#374151",
            zIndex: 0,
            flexShrink: 0,
            boxSizing: "border-box",
          }}
        >
          +{overflowCount}
        </div>
      )}
    </div>
  );
}

